from dataclasses import dataclass, field
from typing import List, Dict, Optional, Tuple


@dataclass
class Instruction:
    op: str
    rd: int = 0
    rs1: int = 0
    rs2: int = 0
    index: int = 0

    @property
    def is_load(self) -> bool:
        return self.op in ('lw', 'lh', 'lb', 'lhu', 'lbu')

    @property
    def writes_register(self) -> bool:
        return self.op not in ('sw', 'sh', 'sb', 'beq', 'bne', 'blt', 'bge')

    def __repr__(self) -> str:
        if self.op == 'nop':
            return 'nop'
        return f"{self.op} x{self.rd}, x{self.rs1}, x{self.rs2}"


NOP = Instruction(op='nop', rd=0, rs1=0, rs2=0, index=-1)


@dataclass
class PipelineState:
    IF: Optional[Instruction] = None
    ID: Optional[Instruction] = None
    EX: Optional[Instruction] = None
    MEM: Optional[Instruction] = None
    WB: Optional[Instruction] = None


class PipelineSimulator:
    def __init__(self, instructions: List[Dict]):
        self.program: List[Instruction] = []
        for i, inst in enumerate(instructions):
            self.program.append(Instruction(
                op=inst['op'],
                rd=inst.get('rd', 0),
                rs1=inst.get('rs1', 0),
                rs2=inst.get('rs2', 0),
                index=i
            ))
        self.pc: int = 0
        self.cycle: int = 0
        self.stalls: int = 0
        self.state = PipelineState()
        self.trace: List[Dict] = []

    def detect_load_use_hazard(self) -> bool:
        ex = self.state.EX
        id_inst = self.state.ID
        if ex is None or id_inst is None:
            return False
        if not ex.is_load:
            return False
        if ex.rd == 0:
            return False
        if not ex.writes_register:
            return False
        if ex.rd == id_inst.rs1 or ex.rd == id_inst.rs2:
            return True
        return False

    def detect_forwarding(self) -> List[str]:
        forwards = []
        id_inst = self.state.ID
        if id_inst is None:
            return forwards

        # Check EX/MEM forwarding (instruction in MEM stage, was in EX last cycle)
        ex_mem = self.state.EX
        if ex_mem is not None and ex_mem.writes_register and ex_mem.rd != 0:
            if ex_mem.rd == id_inst.rs1:
                forwards.append('EX/MEM -> rs1')
            if ex_mem.rd == id_inst.rs2:
                forwards.append('EX/MEM -> rs2')

        # Check MEM/WB forwarding (instruction in MEM stage)
        mem_wb = self.state.MEM
        if mem_wb is not None and mem_wb.writes_register and mem_wb.rd != 0:
            if mem_wb.rd == id_inst.rs1 and 'EX/MEM -> rs1' not in forwards:
                forwards.append('MEM/WB -> rs1')
            if mem_wb.rd == id_inst.rs2 and 'EX/MEM -> rs2' not in forwards:
                forwards.append('MEM/WB -> rs2')

        return forwards

    def _fetch_next(self) -> Optional[Instruction]:
        if self.pc < len(self.program):
            inst = self.program[self.pc]
            self.pc += 1
            return inst
        return None

    def advance_pipeline(self) -> None:
        self.cycle += 1
        hazard = self.detect_load_use_hazard()

        if hazard:
            self.stalls += 1
            # WB and MEM advance normally
            self.state.WB = self.state.MEM
            self.state.MEM = self.state.EX
            # Insert bubble into EX
            self.state.EX = NOP
            # IF and ID stall (keep their current values)
            # PC does not advance
        else:
            self.state.WB = self.state.MEM
            self.state.MEM = self.state.EX
            self.state.EX = self.state.ID
            self.state.ID = self.state.IF
            self.state.IF = self._fetch_next()

        self.trace.append({
            'cycle': self.cycle,
            'IF': repr(self.state.IF) if self.state.IF else '-',
            'ID': repr(self.state.ID) if self.state.ID else '-',
            'EX': repr(self.state.EX) if self.state.EX else '-',
            'MEM': repr(self.state.MEM) if self.state.MEM else '-',
            'WB': repr(self.state.WB) if self.state.WB else '-',
            'stall': hazard,
            'forwarding': self.detect_forwarding() if not hazard else []
        })

    def run(self) -> Dict:
        # Fetch first instruction
        self.state.IF = self._fetch_next()

        # Run until pipeline is fully drained
        max_cycles = len(self.program) * 3 + 10  # Safety limit
        while self.cycle < max_cycles:
            self.advance_pipeline()
            # Check if pipeline is empty
            if (self.state.IF is None and self.state.ID is None and
                self.state.EX is None and self.state.MEM is None and
                self.state.WB is None):
                break

        num_instructions = len(self.program)
        cpi = self.cycle / num_instructions if num_instructions > 0 else 0

        return {
            'total_cycles': self.cycle,
            'total_instructions': num_instructions,
            'cpi': round(cpi, 2),
            'stalls': self.stalls,
            'trace': self.trace
        }

from typing import List, Tuple, Dict
import random


class OneBitPredictor:
    def __init__(self, table_size: int = 1024):
        self.table_size = table_size
        self.table: List[bool] = [False] * table_size

    def _index(self, pc: int) -> int:
        return (pc >> 2) % self.table_size

    def predict(self, pc: int) -> bool:
        return self.table[self._index(pc)]

    def update(self, pc: int, taken: bool) -> None:
        self.table[self._index(pc)] = taken


class TwoBitPredictor:
    def __init__(self, table_size: int = 1024):
        self.table_size = table_size
        self.table: List[int] = [1] * table_size

    def _index(self, pc: int) -> int:
        return (pc >> 2) % self.table_size

    def predict(self, pc: int) -> bool:
        return self.table[self._index(pc)] >= 2

    def update(self, pc: int, taken: bool) -> None:
        idx = self._index(pc)
        if taken:
            self.table[idx] = min(3, self.table[idx] + 1)
        else:
            self.table[idx] = max(0, self.table[idx] - 1)


class TournamentPredictor:
    def __init__(self, table_size: int = 1024, history_len: int = 10):
        self.table_size = table_size
        self.history_len = history_len
        self.history_mask = (1 << history_len) - 1
        self.local_table: List[int] = [1] * table_size
        self.global_history: int = 0
        self.global_table: List[int] = [1] * table_size
        self.chooser: List[int] = [2] * table_size

    def _pc_index(self, pc: int) -> int:
        return (pc >> 2) % self.table_size

    def _global_index(self, pc: int) -> int:
        return ((pc >> 2) ^ self.global_history) % self.table_size

    def predict(self, pc: int) -> bool:
        pc_idx = self._pc_index(pc)
        local_pred = self.local_table[pc_idx] >= 2
        global_pred = self.global_table[self._global_index(pc)] >= 2
        use_global = self.chooser[pc_idx] >= 2
        return global_pred if use_global else local_pred

    def update(self, pc: int, taken: bool) -> None:
        pc_idx = self._pc_index(pc)
        gi = self._global_index(pc)

        local_pred = self.local_table[pc_idx] >= 2
        global_pred = self.global_table[gi] >= 2

        # Update chooser
        if global_pred == taken and local_pred != taken:
            self.chooser[pc_idx] = min(3, self.chooser[pc_idx] + 1)
        elif local_pred == taken and global_pred != taken:
            self.chooser[pc_idx] = max(0, self.chooser[pc_idx] - 1)

        # Update predictors
        if taken:
            self.local_table[pc_idx] = min(3, self.local_table[pc_idx] + 1)
            self.global_table[gi] = min(3, self.global_table[gi] + 1)
        else:
            self.local_table[pc_idx] = max(0, self.local_table[pc_idx] - 1)
            self.global_table[gi] = max(0, self.global_table[gi] - 1)

        # Update global history
        self.global_history = ((self.global_history << 1) | int(taken)) & self.history_mask


def generate_loop_trace(loop_count: int, iterations: int,
                        base_pc: int = 0x1000) -> List[Tuple[int, bool]]:
    trace = []
    for _ in range(loop_count):
        for i in range(iterations):
            taken = (i < iterations - 1)
            trace.append((base_pc, taken))
    return trace


def generate_correlated_trace(length: int, base_pc: int = 0x2000) -> List[Tuple[int, bool]]:
    trace = []
    for i in range(length):
        a_taken = (i % 3 != 0)
        trace.append((base_pc, a_taken))
        b_taken = not a_taken
        trace.append((base_pc + 0x10, b_taken))
    return trace


class BranchPredictorBenchmark:
    def run(self, predictors: Dict[str, object],
            trace: List[Tuple[int, bool]]) -> Dict[str, Dict]:
        results = {}
        for name, pred in predictors.items():
            correct = 0
            total = 0
            for pc, taken in trace:
                prediction = pred.predict(pc)
                if prediction == taken:
                    correct += 1
                total += 1
                pred.update(pc, taken)
            results[name] = {
                'accuracy': correct / total if total > 0 else 0.0,
                'correct': correct,
                'total': total,
                'mispredictions': total - correct
            }
        return results

from dataclasses import dataclass
from typing import List, Dict, Tuple
from enum import Enum


class HazardType(Enum):
    RAW = "RAW"
    WAR = "WAR"
    WAW = "WAW"


@dataclass
class Hazard:
    hazard_type: HazardType
    source_index: int
    target_index: int
    register: int
    distance: int
    needs_stall: bool
    forwarding_path: str


@dataclass
class InstructionInfo:
    index: int
    op: str
    rd: int
    rs1: int
    rs2: int
    reads: List[int]
    writes: List[int]
    is_load: bool
    is_store: bool


def parse_instruction(index: int, inst: Dict) -> InstructionInfo:
    op = inst['op']
    rd = inst.get('rd', 0)
    rs1 = inst.get('rs1', 0)
    rs2 = inst.get('rs2', 0)

    load_ops = {'lw', 'lh', 'lb', 'lhu', 'lbu'}
    store_ops = {'sw', 'sh', 'sb'}
    branch_ops = {'beq', 'bne', 'blt', 'bge', 'bltu', 'bgeu'}
    i_type_ops = {'addi', 'andi', 'ori', 'xori', 'slli', 'srli', 'srai', 'slti', 'sltiu'}

    is_load = op in load_ops
    is_store = op in store_ops

    reads = []
    writes = []

    if op in store_ops:
        if rs1 != 0: reads.append(rs1)
        if rs2 != 0: reads.append(rs2)
    elif op in branch_ops:
        if rs1 != 0: reads.append(rs1)
        if rs2 != 0: reads.append(rs2)
    elif op in load_ops or op in i_type_ops:
        if rs1 != 0: reads.append(rs1)
        if rd != 0: writes.append(rd)
    else:  # R-type
        if rs1 != 0: reads.append(rs1)
        if rs2 != 0: reads.append(rs2)
        if rd != 0: writes.append(rd)

    return InstructionInfo(
        index=index, op=op, rd=rd, rs1=rs1, rs2=rs2,
        reads=reads, writes=writes,
        is_load=is_load, is_store=is_store
    )


class HazardAnalyzer:
    def __init__(self, instructions: List[Dict]):
        self.instructions = [
            parse_instruction(i, inst) for i, inst in enumerate(instructions)
        ]

    def find_all_hazards(self) -> List[Hazard]:
        hazards = []
        n = len(self.instructions)

        for i in range(n):
            for j in range(i + 1, min(i + 4, n)):  # Only check distance <= 3
                inst_i = self.instructions[i]
                inst_j = self.instructions[j]
                distance = j - i

                # RAW: j reads what i writes
                for reg in inst_i.writes:
                    if reg in inst_j.reads:
                        if distance == 1 and inst_i.is_load:
                            needs_stall = True
                            path = 'none'
                        elif distance == 1:
                            needs_stall = False
                            path = 'EX->EX'
                        elif distance == 2:
                            needs_stall = False
                            path = 'MEM->EX'
                        else:
                            needs_stall = False
                            path = 'register file'
                        hazards.append(Hazard(
                            hazard_type=HazardType.RAW,
                            source_index=i,
                            target_index=j,
                            register=reg,
                            distance=distance,
                            needs_stall=needs_stall,
                            forwarding_path=path
                        ))

                # WAR: j writes what i reads
                for reg in inst_j.writes:
                    if reg in inst_i.reads:
                        hazards.append(Hazard(
                            hazard_type=HazardType.WAR,
                            source_index=i,
                            target_index=j,
                            register=reg,
                            distance=distance,
                            needs_stall=False,
                            forwarding_path='N/A'
                        ))

                # WAW: j writes what i writes
                for reg in inst_i.writes:
                    if reg in inst_j.writes:
                        hazards.append(Hazard(
                            hazard_type=HazardType.WAW,
                            source_index=i,
                            target_index=j,
                            register=reg,
                            distance=distance,
                            needs_stall=False,
                            forwarding_path='N/A'
                        ))

        return hazards

    def summary(self) -> Dict:
        hazards = self.find_all_hazards()
        raw_count = sum(1 for h in hazards if h.hazard_type == HazardType.RAW)
        war_count = sum(1 for h in hazards if h.hazard_type == HazardType.WAR)
        waw_count = sum(1 for h in hazards if h.hazard_type == HazardType.WAW)
        stalls_needed = sum(1 for h in hazards if h.needs_stall)

        return {
            'raw_count': raw_count,
            'war_count': war_count,
            'waw_count': waw_count,
            'stalls_needed': stalls_needed,
            'hazards': hazards
        }

from typing import List, Dict, Tuple


class PerformanceAnalyzer:
    def amdahl_speedup(self, parallel_fraction: float, num_processors: int) -> float:
        serial = 1.0 - parallel_fraction
        return 1.0 / (serial + parallel_fraction / num_processors)

    def gustafson_speedup(self, serial_fraction: float, num_processors: int) -> float:
        return num_processors - (num_processors - 1) * serial_fraction

    def amdahl_max_speedup(self, parallel_fraction: float) -> float:
        serial = 1.0 - parallel_fraction
        if serial == 0:
            return float('inf')
        return 1.0 / serial

    def find_diminishing_point(self, parallel_fraction: float,
                                threshold: float = 0.01) -> int:
        for n in range(1, 10001):
            s_n = self.amdahl_speedup(parallel_fraction, n)
            s_n1 = self.amdahl_speedup(parallel_fraction, n + 1)
            if s_n1 - s_n < threshold:
                return n
        return 10000

    def cost_optimal_processors(self, parallel_fraction: float,
                                 cost_per_processor: float,
                                 value_per_speedup: float,
                                 max_processors: int = 128) -> Dict:
        best_n = 1
        best_value = float('-inf')
        best_speedup = 1.0

        for n in range(1, max_processors + 1):
            speedup = self.amdahl_speedup(parallel_fraction, n)
            net_value = value_per_speedup * speedup - cost_per_processor * n
            if net_value > best_value:
                best_value = net_value
                best_n = n
                best_speedup = speedup

        return {
            'optimal_n': best_n,
            'max_net_value': round(best_value, 2),
            'speedup_at_optimal': round(best_speedup, 2)
        }
